select 
from paotuixiangmu p
left join paotuifenlei f on p.fenlei_id = f.id
left join user u on p.user_id = u.id
left join shangjia s on p.shangjia_id = s.id


        and (p.title like concat('%',#{keyword},'%') or p.content like concat('%',#{keyword},'%'))

    and p.fenlei_id = #{fenleiId}
    and p.status = #{status}
    and p.user_id = #{userId}
    and p.shangjia_id = #{shangjiaId}

order by p.id desc

